"""Graphify测试项目 - 简单的数据处理工具"""

class DataProcessor:
    """数据处理类，负责清洗和转换数据"""

    def __init__\(self, name\):
        self.name = name
        self.data = []

    def load_data\(self, source\):
        """从源加载数据"""
        # NOTE: 这里应该有错误处理
        with open\(source, 'r'\) as f:
            self.data = f.readlines\(\)
        return True

    def clean_data\(self\):
        """清洗数据，去除空白和注释"""
        cleaned = []
        for line in self.data:
            line = line.strip\(\)
            if line and not line.startswith\('#'\):
                cleaned.append\(line\)
        self.data = cleaned
        return cleaned

    def transform_data\(self, func\):
        """使用提供的函数转换数据"""
        # IMPORTANT: 这个函数应该是纯函数，避免副作用
        return [func\(item\) for item in self.data]

class DataAnalyzer:
    """数据分析类，提供统计分析功能"""

    def __init__\(self, processor\):
        self.processor = processor
        self.stats = {}

    def calculate_stats\(self\):
        """计算基本统计信息"""
        data = self.processor.data
        self.stats = {
            'count': len\(data\),
            'avg_length': sum\(len\(item\) for item in data\) / len\(data\) if data else 0
        }
        return self.stats

    def find_patterns\(self\):
        """查找数据中的模式"""
        # TODO: 实现更复杂的模式识别
        patterns = set\(\)
        for item in self.processor.data:
            if len\(item\) > 10:
                patterns.add\('long'\)
            else:
                patterns.add\('short'\)
        return patterns

def main\(\):
    """主函数，演示数据处理流程"""
    processor = DataProcessor\("test"\)

    # HACK: 为了测试使用假数据
    processor.data = ["test data", "another line", "# comment", "short"]

    cleaned = processor.clean_data\(\)
    analyzer = DataAnalyzer\(processor\)

    print\(f"Processed {len\(cleaned\)} items"\)
    print\(f"Stats: {analyzer.calculate_stats\(\)}"\)
    print\(f"Patterns: {analyzer.find_patterns\(\)}"\)

if __name__ == "__main__":
    main\(\)
EOF
echo "✅ 测试代码创建成功")
